  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result.is_ok()) {
    return 1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result.is_ok()) {
    return 1; // Transaction start failed
  }

  // 3. Construct and execute the delete statement with where condition
  auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");
  auto delete_result = delete_stmt(conn);
  if (!delete_result.is_ok()) {
    conn->rollback(); // Rollback on delete failure
    return 1; // Delete operation failed
  }

  // 4. Commit the transaction
  auto commit_result = conn->commit();
  if (!commit_result.is_ok()) {
    conn->rollback(); // Rollback on commit failure
    return 1; // Commit failed
  }

