```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // 2. Create tables if they don't exist
    (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
    (sqlgen::create_table<Post> | sqlgen::if_not_exists)(conn);

    // 3. Build and execute the query
    auto result = (sqlgen::select_from<User, "u">("user_id"_c, "username"_c)
        | sqlgen::inner_join<Post, "p">("user_id"_c == "user_id"_c)
        | sqlgen::where("created_at"_c >= "2025-12-01" && "created_at"_c <= "2025-12-31")
        | sqlgen::distinct
        | sqlgen::to<std::vector<ActiveUser>>)(conn).value();

    return result;
}

}  // namespace query_active_users_posts
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Creation**: Uses `sqlgen::create_table<T> | sqlgen::if_not_exists` pattern to safely create tables
3. **Query Construction**: 
   - Uses `sqlgen::select_from` with table alias "u" for User table
   - Applies `sqlgen::inner_join` with table alias "p" for Post table
   - Uses `sqlgen::where` with date range comparison using `>=` and `<=` operators
   - Applies `sqlgen::distinct` to eliminate duplicate users
   - Maps results to `ActiveUser` struct using `sqlgen::to<std::vector<ActiveUser>>`
4. **Column References**: Uses string literals with `_c` suffix (`"user_id"_c`, `"username"_c`, `"created_at"_c`) for column specification
5. **Join Condition**: Uses equality comparison between user IDs from both tables
6. **Date Filtering**: Implements the specified date range using string literals for the date values

The implementation follows the sqlgen library patterns demonstrated in the reference materials, particularly the test case structure and query building approach shown in the `test_joins_two_tables.cpp` example.

