  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // 2. Create tables using sqlgen::write
  auto write_result = sqlgen::write(conn, std::vector<Course>{});
  if (!write_result) {
    throw std::runtime_error("Failed to create Course table");
  }

  write_result = sqlgen::write(conn, std::vector<Enrollment>{});
  if (!write_result) {
    throw std::runtime_error("Failed to create Enrollment table");
  }

  // 3. Perform the query using sqlgen::read with appropriate chaining
  auto query = sqlgen::read<std::vector<CourseStatsView>>(
    sqlgen::select_from<Course, "c">(
      "c"_t1.title,
      sqlgen::count().as<"student_count">(),
      sqlgen::avg("e"_t2.grade).as<"avg_grade">()
    )
    | sqlgen::left_join<Enrollment, "e">("c"_t1.course_id == "e"_t2.course_id)
    | sqlgen::group_by("c"_t1.course_id, "c"_t1.title)
    | sqlgen::to<std::vector<CourseStatsView>>
  );

  auto result = query(*conn);
  if (!result) {
    throw std::runtime_error("Query failed");
  }

  // Convert results to CourseStats format
  std::vector<CourseStats> stats;
  for (const auto& view : *result) {
    stats.push_back(CourseStats{
      .title = view.title,
      .student_count = view.student_count,
      .avg_grade = view.avg_grade
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
