#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Begin transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    try {
        // Create update statement with set operations
        auto update_stmt = sqlgen::update<Document>(
            sqlgen::set(&Document::is_deleted, 1),
            sqlgen::set(&Document::deleted_at, sqlgen::CURRENT_TIMESTAMP)
        );

        // Apply where condition with IN clause
        auto where_condition = sqlgen::where(
            sqlgen::col<&Document::doc_id>().in(ids)
        );

        // Combine update statement with where condition
        auto full_update = update_stmt | where_condition;

        // Execute the update
        auto result = full_update(conn);

        if (!result) {
            conn->rollback();
            return false;
        }

        // Commit transaction
        return conn->commit().is_success();

    } catch (...) {
        // Rollback on any exception
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
