    auto mutual_friends_query = sqlgen::select_from<User, "u1">("username"_t1.as<"user1_name">(), "username"_t2.as<"user2_name">())
        | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user1_id"_t1)
