          cos("discount_rate"_c).as<"cos_discount">(),
          tan("discount_rate"_c).as<"tan_discount">(),
          sqrt(cast<double>("quantity"_c)).as<"sqrt_quantity">()) |
      to<std::vector<MathAnalysis>>;

