inline std::string left_join_explicit() {
  using namespace sqlgen::literals;

  // Build the LEFT JOIN query using sqlgen
  auto query = sqlgen::select_from<User>("id"_t1, "name"_t1)
             | sqlgen::left_join<Post>("id"_t1 == "user_id"_t2);

  // Convert the query to SQL string
